    name: "list_by_status",
    setup: [
        "create 'Open issue'",
        "create 'Closed issue'",
        "close <id2>",
    ],
    br_command: "br list --status=open --json",
    bd_command: "bd list --status=open --json",
    compare: NormalizedJson,
}
```

#### 3. Dependency Tests
```rust
conformance_test! {
    name: "dep_blocking",
    setup: [
        "create 'Blocker'",
        "create 'Blocked'",
        "dep add <id2> <id1>",
    ],
    br_command: "br blocked --json",
    bd_command: "bd blocked --json",
    compare: ContainsFields(vec!["blocked_by"]),
}
```

#### 4. Sync Tests
```rust
conformance_test! {
    name: "sync_roundtrip",
    setup: [
        "create 'Issue 1'",
        "create 'Issue 2'",
        "dep add <id2> <id1>",
    ],
    test_sequence: [
        // Export from br
        ("br sync --flush-only", None),
        // Import to bd
        ("bd sync --import-only", None),
        // Verify bd sees same data
        ("bd list --json", "br list --json"),
    ],
    compare: NormalizedJson,
}
```

### Running Conformance Tests
```bash
